(function(){'use strict';if(window.siteBroadcast)return;var script=document.querySelector('script[data-broadcast-room]');if(!script)return;var ROOM=script.dataset.broadcastRoom || '';var PUBPEM=script.dataset.broadcastPubkey || '';if(!ROOM || !PUBPEM)return;function host(){return document.querySelector('[data-broadcast]');}function video(){var h=host();return h && h.querySelector('[data-broadcast-video]');}function waitEl(){var h=host();return h && h.querySelector('[data-broadcast-wait]');}function unmuteEl(){var h=host();return h && h.querySelector('[data-broadcast-unmute]');}function setState(s){var h=host();if(h)h.dataset.state=s;}function onStream(stream){var v=video(),w=waitEl(),u=unmuteEl();if(!v)return;if(stream){if(v.srcObject !==stream)v.srcObject=stream;v.muted=true;var p=v.play();if(p && p.catch)p.catch(function(){});setState('live');if(w)w.hidden=true;if(u)u.hidden=false;}else{v.srcObject=null;setState('waiting');if(w)w.hidden=false;if(u)u.hidden=true;}}document.addEventListener('click',function(e){if(!e.target.closest('[data-broadcast-unmute]'))return;var v=video();if(!v)return;v.muted=false;var p=v.play();if(p && p.catch)p.catch(function(){});var u=unmuteEl();if(u)u.hidden=true;});setState('waiting');function begin(){if(!window.siteComm || !window.siteComm.signedReceiver)return false;window.siteBroadcast={teardown:function(){onStream(null);}};window.siteComm.signedReceiver(ROOM,PUBPEM,{onStream:onStream}).then(function(r){if(r)window.siteBroadcast.handle=r;});return true;}if(!begin()){var tries=0;var t=setInterval(function(){if(begin()|| ++tries>50)clearInterval(t);},100);}})();
